CREATE OR REPLACE FUNCTION discounted(price NUMERIC, pct NUMERIC)
RETURNS NUMERIC
LANGUAGE sql
IMMUTABLE STRICT
AS $$
  SELECT ROUND(price - price * pct / 100, 2);
$$;

