CREATE OR REPLACE FUNCTION stock_status(p_id INT)
RETURNS TEXT
LANGUAGE plpgsql
AS $$
DECLARE
  v_stock INT;
BEGIN
  SELECT stock INTO v_stock FROM products WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN 'unknown';
  ELSIF v_stock = 0 THEN
    RETURN 'out';
  ELSIF v_stock <= 2 THEN
    RETURN 'low';
  ELSIF v_stock <= 9 THEN
    RETURN 'ok';
  ELSE
    RETURN 'plenty';
  END IF;
END;
$$;

SELECT name, stock, stock_status(id) AS status
FROM products
ORDER BY name;

SELECT stock_status(99) AS missing_product;

