CREATE OR REPLACE FUNCTION products_below(p_max NUMERIC)
RETURNS TABLE(name TEXT, price NUMERIC, status TEXT)
LANGUAGE plpgsql
STABLE
AS $$
BEGIN
  IF p_max < 0 THEN
    RETURN;
  END IF;

  RETURN QUERY
    SELECT p.name, p.price, stock_status(p.id)
    FROM products p
    WHERE p.price <= p_max
    ORDER BY p.price DESC;
END;
$$;

