CREATE OR REPLACE PROCEDURE restock_all(p_amount INT, INOUT p_touched INT DEFAULT 0)
LANGUAGE plpgsql
AS $$
DECLARE
  rec RECORD;
BEGIN
  p_touched := 0;

  FOR rec IN SELECT id FROM products ORDER BY id LOOP
    UPDATE products SET stock = stock + p_amount WHERE id = rec.id;
    p_touched := p_touched + 1;

    -- Commit in batches so a later failure cannot undo earlier work.
    IF p_touched % 2 = 0 THEN
      COMMIT;
    END IF;
  END LOOP;

  COMMIT;
END;
$$;

CALL restock_all(5, 0);

SELECT name, stock FROM products ORDER BY name;

-- A function may not end a transaction.
CREATE OR REPLACE FUNCTION try_commit() RETURNS VOID LANGUAGE plpgsql AS $$
BEGIN
  COMMIT;
END;
$$;

DO $$
BEGIN
  PERFORM try_commit();
  RAISE NOTICE 'unexpected: commit succeeded inside a function';
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'function commit failed with SQLSTATE %', SQLSTATE;
END;
$$;

