CREATE OR REPLACE FUNCTION add_customer(p_id INT, p_name TEXT, p_email TEXT)
RETURNS TEXT
LANGUAGE plpgsql
AS $$
BEGIN
  IF position('@' IN p_email) = 0 THEN
    RAISE EXCEPTION 'invalid email' USING ERRCODE = '22000';
  END IF;

  INSERT INTO customers (id, name, email) VALUES (p_id, p_name, p_email);
  RETURN 'created';

EXCEPTION
  WHEN unique_violation THEN
    RETURN 'duplicate';
  WHEN OTHERS THEN
    RETURN 'error:' || SQLSTATE;
END;
$$;

