CREATE OR REPLACE FUNCTION log_product_change()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    INSERT INTO audit_log (action, entity, entity_id) VALUES (lower(TG_OP), 'product', OLD.id);
  ELSE
    INSERT INTO audit_log (action, entity, entity_id) VALUES (lower(TG_OP), 'product', NEW.id);
  END IF;
  RETURN NULL;
END;
$$;

CREATE TRIGGER trg_product_audit
AFTER INSERT OR UPDATE OR DELETE ON products
FOR EACH ROW EXECUTE FUNCTION log_product_change();

