CREATE OR REPLACE FUNCTION tidy_customer()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  NEW.name  := btrim(NEW.name);
  NEW.email := lower(btrim(NEW.email));

  IF NEW.name = '' THEN
    RETURN NULL;          -- discard the row
  END IF;

  RETURN NEW;             -- store the rewritten row
END;
$$;

CREATE TRIGGER trg_tidy_customer
BEFORE INSERT OR UPDATE ON customers
FOR EACH ROW EXECUTE FUNCTION tidy_customer();

