CREATE OR REPLACE FUNCTION row_count(p_table TEXT)
RETURNS BIGINT
LANGUAGE plpgsql
AS $$
DECLARE
  v_count BIGINT;
BEGIN
  EXECUTE format('SELECT count(*) FROM %I', p_table) INTO v_count;
  RETURN v_count;
END;
$$;

CREATE OR REPLACE FUNCTION find_by(p_table TEXT, p_column TEXT, p_value TEXT)
RETURNS BIGINT
LANGUAGE plpgsql
AS $$
DECLARE
  v_count BIGINT;
BEGIN
  EXECUTE format('SELECT count(*) FROM %I WHERE %I = $1', p_table, p_column)
    INTO v_count
    USING p_value;
  RETURN v_count;
END;
$$;

