CREATE OR REPLACE FUNCTION markup_loop(p_pct NUMERIC)
RETURNS INT
LANGUAGE plpgsql
AS $$
DECLARE
  rec     RECORD;
  v_rows  INT := 0;
BEGIN
  FOR rec IN SELECT id, price FROM products ORDER BY id LOOP
    UPDATE products
       SET price = ROUND(rec.price * (1 + p_pct / 100), 2)
     WHERE id = rec.id;
    v_rows := v_rows + 1;
  END LOOP;
  RETURN v_rows;
END;
$$;

CREATE OR REPLACE FUNCTION markup_set(p_pct NUMERIC)
RETURNS INT
LANGUAGE plpgsql
AS $$
DECLARE
  v_rows INT;
BEGIN
  UPDATE products SET price = ROUND(price * (1 + p_pct / 100), 2);
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  RETURN v_rows;
END;
$$;

SELECT markup_loop(10) AS loop_rows;
SELECT name, price FROM products ORDER BY name;

SELECT markup_set(-10) AS set_rows;
SELECT name, price FROM products ORDER BY name;

SELECT (SELECT markup_loop(0)) = (SELECT markup_set(0)) AS same_rows;

