CREATE OR REPLACE PROCEDURE place_order(p_customer INT, p_product INT, p_qty INT, INOUT p_result TEXT DEFAULT '')
LANGUAGE plpgsql
AS $$
DECLARE
  v_price  NUMERIC;
  v_rows   INT;
  v_order  INT;
  v_dummy  INT;
BEGIN
  IF p_qty IS NULL OR p_qty <= 0 THEN
    RAISE EXCEPTION 'quantity must be positive' USING ERRCODE = '22023';
  END IF;

  SELECT id INTO v_dummy FROM customers WHERE id = p_customer;
  IF NOT FOUND THEN
    p_result := 'no-customer';
    RETURN;
  END IF;

  SELECT price INTO v_price FROM products WHERE id = p_product;
  IF NOT FOUND THEN
    p_result := 'no-product';
    RETURN;
  END IF;

  -- Check and reserve in ONE statement: the WHERE clause is the guard, so two
  -- concurrent callers cannot both pass it and drive the stock negative.
  UPDATE products
     SET stock = stock - p_qty
   WHERE id = p_product AND stock >= p_qty;
  GET DIAGNOSTICS v_rows = ROW_COUNT;

  IF v_rows = 0 THEN
    p_result := 'insufficient-stock';
    RETURN;
  END IF;

  INSERT INTO orders (customer_id, total, status)
  VALUES (p_customer, v_price * p_qty, 'placed')
  RETURNING id INTO v_order;

  INSERT INTO order_items (order_id, product_id, qty) VALUES (v_order, p_product, p_qty);
  INSERT INTO audit_log (action, entity, entity_id) VALUES ('order', 'order', v_order);

  p_result := 'ok:' || v_order;

EXCEPTION
  WHEN OTHERS THEN
    p_result := 'error:' || SQLSTATE;
END;
$$;

CALL place_order(1, 1, 2);
CALL place_order(1, 3, 99);
CALL place_order(1, 1, 0);
CALL place_order(1, 42, 1);

SELECT name, stock FROM products ORDER BY name;
SELECT count(*) AS orders FROM orders;
SELECT count(*) AS audit_rows FROM audit_log;

